BuffConfig = {}
BuffConfig.buffs = {}

function BuffConfig:init(buffConfig)
    for _, config in pairs(buffConfig) do
        local item = {}
        item.id = tonumber(config.id)
        item.type = tonumber(config.type)
        item.duration = tonumber(config.duration)
        item.value = tonumber(config.value) or 0
        item.timeInterval = tonumber(config.timeInterval)
        item.endValue = tonumber(config.endValue)
        item.deadDisappear = tonumber(config.deadDisappear)
        item.overlayType = tonumber(config.overlayType)
        item.image = tostring(config.image)
        table.insert(self.buffs, item)
    end
end

function BuffConfig:getBuffByType(buffType)
    for _, buffConfig in pairs(self.buffs) do
        if buffConfig.type == buffType then
            return buffConfig
        end
    end
end